(function(){const form=document.getElementById('vh360-bible-import-form');if(!form)return;const out=document.getElementById('vh360-bible-import-progress');async function api(path,opts){opts=opts||{};opts.headers=Object.assign({'X-WP-Nonce':vh360StudioBibleAdmin.nonce},opts.headers||{});const r=await fetch(vh360StudioBibleAdmin.restRoot+path,opts);const j=await r.json();if(!r.ok)throw new Error(j.message||'Request failed');return j;}form.addEventListener('submit',async e=>{e.preventDefault();try{out.textContent='Uploading…';let job=await api('/bible/imports',{method:'POST',body:new FormData(form)});while(!['completed','failed','cancelled'].includes(job.status)){out.textContent=JSON.stringify(job,null,2);job=await api('/bible/imports/'+job.id+'/batch',{method:'POST'});}out.textContent=JSON.stringify(job,null,2);if(job.status==='completed')location.reload();}catch(err){out.textContent=err.message;}});})();
